VALUES
  ('judicial-57112235-moex-00757', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依外役監條例有關受刑人遴選之規定，下列敘述何者錯誤？', '["受有期徒刑之執行逾2個月", "刑期7年以下，或刑期逾7年未滿15年而累進處遇進至第四級以上，或刑期15年以上而累進處遇 進至第三級以上", "無期徒刑累進處遇應進至第一級", "有悛悔實據，身心健康適於外役作業"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00758', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄對受刑人實施強制營養或醫療之要件，依監獄行刑法之規定，下列敘述何者錯誤？', '["受刑人有拒絕飲食或未依醫囑服藥", "有危及生命之虞時", "監獄應即請醫師進行診療", "得由護理人員施以強制營養或採取醫療上必要之強制措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00759', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄對於受刑人應施以教化，下列敘述何者正確？', '["教化僅參酌受刑人之前科與學歷，施以適當之輔導與教育", "輔導內容由監獄之教誨師、心理師與社工師設計規劃，僅以個別輔導方式為之", "監獄得自行或與學校合作辦理補習教育、進修教育或推廣教育", "監獄僅能延聘社會知名人士為志工，協助教化工作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00760', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人有關信仰宗教之規定，下列敘述何者正確？', '["監獄應依受刑人請求安排其熟識之宗教師實施教誨", "監獄應邀請有名望之宗教人士舉行有助於受刑人之宗教活動", "受刑人得持有與其宗教信仰有關之任何物品或典籍，並無例外", "受刑人得因宗教信仰，請求監獄提供適當之飲食"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00761', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法規定，作業收入扣除作業支出後之作業賸餘，提多少比例為勞作金？', '["百分之四十", "百分之五十", "百分之六十", "百分之七十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00762', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為避免發生群聚感染，監獄應依監獄行刑法及傳染病防治法落實執行相關感染管制之措施，下列敘述 何者錯誤？', '["隔離治療時間之長短或方式，應遵循醫師之醫囑或衛生主管機關之處分或指導", "經監獄通報有疑似傳染病病人時，地方主管機關應協助監獄預防及處理", "監獄收容來自傳染病流行地或經過其地之受刑人，應為一定期間之隔離；其攜帶物品，得為必要之 處置", "受刑人於指定隔離治療機構施行治療，視為在監執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00763', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法關於作業之規定，下列敘述何者錯誤？', '["作業時間每日不得逾8小時。但有特殊情形，得將作業時間延長之，延長之作業時間連同正常作業 時間，一日不得超過14小時", "受刑人之作業，以勞動能率或作業時間作為課程；其勞動能率應依一般人平均工作產能酌定", "就炊事、打掃及其他需急速之作業者，除受刑人之配偶、直系親屬或三親等內旁系親屬喪亡外，不 停止作業", "受刑人因作業或職業訓練致受傷、罹病、重傷、失能或死亡者，應發給補償金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00764', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及其施行細則有關給養之相關規定，下列敘述何者錯誤？', '["監獄依監獄行刑法第46條第1項提供必要之衣類、寢具、物品及其他器具，不得違反相關衛生、 環境保護或其他法令之規定", "因應氣溫或保健上有必要者，經監獄許可，受刑人得使用自備或送入之衣類、帽、襪、寢具及適當 之保暖用品", "監獄辦理受刑人飲食得參考衛生福利部食品藥物管理署發布之飲食指南建議；必要時，得諮詢營養 師之意見", "受刑人因經濟狀況欠佳，缺乏日常生活必需品者，得請求監獄提供之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00765', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '報請保外醫治受刑人，無法辦理具保、責付、限制住居時，監獄應檢具相關資料通知監獄所在地直轄市、 縣（市）社會福利主管機關辦理轉介安置或為其他必要之處置。下列何者非所指應檢具「相關資料」之 項目？', '["醫療需求", "照護計畫", "照護期程", "財力證明"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00766', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人申請自費於監獄內實施健康檢查之規定，下列敘述何者錯誤？', '["受刑人申請自費於監獄內健康檢查時，得請求監獄准許延請醫事人員實施", "受刑人申請方式，不以書面為限", "實施健康檢查之時間、地點及方式，由監獄依其特性與實際情形決定之", "檢查紀錄應依醫療相關法規製作及保存，並交付監獄留存"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
